import json

# Read the full business data from file
file_path = locals()['var_functions.query_db:8']
with open(file_path, 'r') as f:
    businesses = json.load(f)

print('Total businesses:', len(businesses))

# Filter businesses that accept credit cards
credit_card_businesses = []
for business in businesses:
    if 'attributes' in business and business['attributes'] != 'None' and business['attributes'] is not None:
        attributes = business['attributes']
        if isinstance(attributes, dict) and 'BusinessAcceptsCreditCards' in attributes:
            if attributes['BusinessAcceptsCreditCards'] == 'True':
                credit_card_businesses.append(business)

print('Total credit card businesses:', len(credit_card_businesses))

# Examine a few descriptions to understand format
print('\nSample descriptions:')
for i, business in enumerate(credit_card_businesses[:5]):
    print(f"{i+1}. {business.get('description', 'No description')[:200]}...")

# Simple approach: extract categories from the description
from collections import defaultdict
category_count = defaultdict(int)

for business in credit_card_businesses:
    if 'description' in business and business['description']:
        desc = business['description']

        # Look for comma-separated lists which often indicate categories
        import re

        # Pattern 1: Quoted category lists
        quoted = re.findall(r"['"]([^'"]+)['"]", desc)
        for q in quoted:
            if ',' in q:
                cats = q.split(',')
                for cat in cats:
                    cat = cat.strip()
                    if cat and len(cat) > 3:
                        category_count[cat.lower()] += 1

        # Pattern 2: Simple comma-separated words/phrases at end
        if not quoted:
            # Find parts with multiple commas
            comma_parts = re.findall(r'([^,.]{10,}(?:,\s*[^,.]+){2,})', desc)
            for part in comma_parts:
                cats = part.split(',')
                for cat in cats:
                    cat = cat.strip()
                    if cat and len(cat) > 3:
                        # Clean up common prefixes
                        cat = re.sub(r'^\s*(in|of|for|and|or|the|a|an)\s+', '', cat, flags=re.IGNORECASE)
                        cat = cat.strip()
                        if cat:
                            category_count[cat.lower()] += 1

# Show top categories
if category_count:
    sorted_categories = sorted(category_count.items(), key=lambda x: x[1], reverse=True)
    print('\nTop 10 categories:')
    for cat, count in sorted_categories[:10]:
        print(f"  {cat}: {count}")

    top_category = sorted_categories[0]
    print(f'\nTop category overall: {top_category[0]} ({top_category[1]} businesses)')
else:
    top_category = (None, 0)
    print('\nNo categories found')

result = {
    'credit_card_count': len(credit_card_businesses),
    'top_category_name': top_category[0],
    'top_category_count': top_category[1]
}

print('__RESULT__:')
print(json.dumps(result))

